import time

def wait_for_batch(batch_id: str, poll_interval: int = 60) -> dict:
    """Poll until the batch completes; return final batch object."""
    while True:
        batch = client.batches.retrieve(batch_id)
        print(f"[{batch.status}] completed={batch.request_counts.completed} "
              f"failed={batch.request_counts.failed} "
              f"total={batch.request_counts.total}")
        if batch.status in ("completed", "failed", "expired", "cancelled"):
            return batch
        time.sleep(poll_interval)


def download_results(batch: dict, output_path: str) -> list[dict]:
    """Download and parse the output JSONL."""
    if not batch.output_file_id:
        raise ValueError(f"Batch {batch.id} has no output file (status={batch.status})")

    content = client.files.content(batch.output_file_id).read()
    results = []
    for line in content.decode().splitlines():
        result = json.loads(line)
        results.append({
            "id": result["custom_id"],
            "content": result["response"]["body"]["choices"][0]["message"]["content"],
            "status": "ok" if result["response"]["status_code"] == 200 else "error",
        })

    with open(output_path, "w") as f:
        for r in results:
            f.write(json.dumps(r) + "\n")
    return results
